// PROA · HDV — Apps Script webapp v7
// Incluye diccionario CIE-10 completo (12.634 codigos)
var SHEET_ID = '1ZsjuygpRz1wPhCRxmL8LPLTNOo8kujGXplX8JRs6SZY';
var GID      = '1610260046';

function doGet(e) {
  var action   = (e && e.parameter && e.parameter.action)   || '';
  var callback = (e && e.parameter && e.parameter.callback) || '';
  if (action === 'data')  return serveData(callback);
  if (action === 'cie10') return serveCIE10();
  return serveDashboard();
}

/* ── Datos del Sheet ─────────────────────────────────────────────── */
function serveData(callback) {
  try {
    var ss    = SpreadsheetApp.openById(SHEET_ID);
    var sheet = getSheetByGid(ss, GID);
    if (!sheet) return respond(callback, {error: 'Hoja no encontrada. GID: ' + GID});
    var raw  = sheet.getDataRange().getValues();
    var data = raw.map(function(row) {
      return row.map(function(cell) {
        if (cell instanceof Date) {
          var d  = String(cell.getDate()).padStart(2,'0');
          var mo = String(cell.getMonth()+1).padStart(2,'0');
          var y  = cell.getFullYear();
          var hh = String(cell.getHours()).padStart(2,'0');
          var mm = String(cell.getMinutes()).padStart(2,'0');
          return d+'/'+mo+'/'+y+' '+hh+':'+mm;
        }
        if (cell === null || cell === undefined) return '';
        return String(cell);
      });
    });
    return respond(callback, {ok: true, data: data});
  } catch(err) {
    return respond(callback, {error: err.message});
  }
}

/* ── Diccionario CIE-10 ──────────────────────────────────────────── */
function serveCIE10() {
  var b64 = getCIE10B64();
  var json = Utilities.newBlob(Utilities.base64Decode(b64)).getDataAsString();
  return ContentService.createTextOutput(json).setMimeType(ContentService.MimeType.JSON);
}

