/* ── Dashboard HTML ──────────────────────────────────────────────── */
function serveDashboard() {
  var url  = ScriptApp.getService().getUrl();
  var b64  = getHtmlB64();
  var html = Utilities.newBlob(Utilities.base64Decode(b64)).getDataAsString();
  html = html.replace('%%SCRIPT_URL%%', url);
  return HtmlService
    .createHtmlOutput(html)
    .setTitle('PROA - Hospital Departamental de Villavicencio')
    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL);
}

